
import { initializeApp, getApps, App, cert, ServiceAccount } from 'firebase-admin/app';

// Import the service account key directly from the JSON file.
// This is more robust than hardcoding the key as a string.
import serviceAccountKey from '../../service-account-key.json';

/**
 * Initializes and returns the Firebase Admin App instance.
 * This function is memoized to ensure it's only initialized once.
 */
export function getAdminApp(): App {
  const appName = 'firebase-admin-app-[StakIt]';

  const existingApp = getApps().find(app => app.name === appName);
  if (existingApp) {
    return existingApp;
  }

  // The JSON file is imported as a JavaScript object, which can be passed to cert().
  // We cast it to ServiceAccount to ensure type safety.
  return initializeApp({
    credential: cert(serviceAccountKey as ServiceAccount),
  }, appName);
}
